"""Async wrapper around the `cursor-sdk-bridge` subprocess.

Reuses `BridgeEndpoint.from_discovery` from `_bridge.py` so discovery
validation stays in one place; the only async-specific work is launching the
process and reading the discovery line from stderr without blocking the
event loop.
"""

from __future__ import annotations

import asyncio
import codecs
import os
from typing import Any, Mapping, Sequence

from ._async_connect import post_bridge_shutdown as post_bridge_shutdown_async
from ._bridge import (
    BridgeEndpoint,
    _bridge_subprocess_env,
    parse_discovery_line,
)
from ._local_store import LocalAgentStoreHandler
from ._store_callback import (
    StoreCallbackServer,
    local_store_bridge_argv,
    resolve_store_callback_handler_for_launch,
    store_callback_bridge_argv,
)
from ._tool_callback import ToolCallbackServer, tool_callback_bridge_argv
from .types import CustomTool, LocalAgentOptions
from ._vendor import resolve_bridge_path
from .errors import CursorSDKError


class AsyncBridge:
    """Async-managed `cursor-sdk-bridge` subprocess."""

    def __init__(
        self,
        endpoint: BridgeEndpoint,
        process: asyncio.subprocess.Process | None = None,
        store_callback_server: StoreCallbackServer | None = None,
        tool_callback_server: ToolCallbackServer | None = None,
    ) -> None:
        self.endpoint = endpoint
        self.process = process
        self._store_callback_server = store_callback_server
        self._tool_callback_server = tool_callback_server

    @property
    def store_callback_enabled(self) -> bool:
        return self._store_callback_server is not None

    @property
    def tool_callback_enabled(self) -> bool:
        return self._tool_callback_server is not None

    def register_custom_tools(
        self, agent_id: str, tools: Mapping[str, CustomTool]
    ) -> None:
        if self._tool_callback_server is None:
            raise CursorSDKError("Bridge has no tool callback server")
        self._tool_callback_server.register_agent(agent_id, tools)

    def unregister_custom_tools(self, agent_id: str) -> None:
        if self._tool_callback_server is not None:
            self._tool_callback_server.unregister_agent(agent_id)

    @classmethod
    async def launch(
        cls,
        command: str
        | os.PathLike[str]
        | Sequence[str | os.PathLike[str]]
        | None = None,
        *,
        workspace: str | os.PathLike[str] | None = None,
        state_root: str | os.PathLike[str] | None = None,
        host: str | None = None,
        port: int | None = None,
        timeout: float = 30,
        local: LocalAgentOptions | Mapping[str, Any] | None = None,
        store_handler: LocalAgentStoreHandler | None = None,
    ) -> "AsyncBridge":
        if command is None:
            argv = [resolve_bridge_path()]
        elif isinstance(command, (str, os.PathLike)):
            argv = [os.fspath(command)]
        else:
            argv = [os.fspath(arg) for arg in command]
        if workspace:
            argv.extend(["--workspace", os.fspath(workspace)])
        if state_root:
            argv.extend(["--state-root", os.fspath(state_root)])
        if host:
            argv.extend(["--host", host])
        if port is not None:
            argv.extend(["--port", str(port)])

        store_callback_server: StoreCallbackServer | None = None
        env = dict(_bridge_subprocess_env())
        handler = resolve_store_callback_handler_for_launch(
            local=local,
            store_handler=store_handler,
        )
        if handler is not None:
            # Pass the running loop so async substore methods run on it.
            store_callback_server = StoreCallbackServer(
                handler, loop=asyncio.get_running_loop()
            )
            # argv only, never the subprocess env: the bridge's model-driven
            # shell tools inherit its env, so a token there could be read by a
            # prompt-injected command.
            argv.extend(store_callback_bridge_argv(store_callback_server.endpoint))
        tool_callback_server = ToolCallbackServer(loop=asyncio.get_running_loop())
        argv.extend(tool_callback_bridge_argv(tool_callback_server.endpoint))
        # Bind the store for every operation (create/list/get), like the TS SDK.
        argv.extend(local_store_bridge_argv(local))

        process = await asyncio.create_subprocess_exec(
            *argv,
            stdout=asyncio.subprocess.DEVNULL,
            stderr=asyncio.subprocess.PIPE,
            env=env,
        )
        try:
            discovery = await _read_discovery(process, timeout)
            return cls(
                BridgeEndpoint.from_discovery(discovery),
                process,
                store_callback_server,
                tool_callback_server,
            )
        except Exception:
            if store_callback_server is not None:
                store_callback_server.close()
            if tool_callback_server is not None:
                tool_callback_server.close()
            await _terminate_process(process)
            raise

    async def aclose(self) -> None:
        if self.process is None:
            return
        # Direct Connect RPC instead of constructing AsyncClient: the full
        # client would force a function-local import to break the
        # `_async_bridge -> _async_client -> _async_bridge` cycle, and we
        # only need this single Shutdown RPC. The helper closes the
        # temporary httpx pool and swallows transport errors so we always
        # proceed to terminate.
        await post_bridge_shutdown_async(
            self.endpoint.url, self.endpoint.auth_token, grace_seconds=0
        )
        await _terminate_process(self.process)
        self.process = None
        if self._store_callback_server is not None:
            self._store_callback_server.close()
            self._store_callback_server = None
        if self._tool_callback_server is not None:
            self._tool_callback_server.close()
            self._tool_callback_server = None

    async def __aenter__(self) -> "AsyncBridge":
        return self

    async def __aexit__(self, *exc: Any) -> None:
        await self.aclose()


async def _read_discovery(
    process: asyncio.subprocess.Process, timeout: float
) -> Mapping[str, Any]:
    if process.stderr is None:
        raise CursorSDKError("Bridge process stderr is unavailable")

    decoder = codecs.getincrementaldecoder("utf-8")(errors="replace")
    stderr_lines: list[str] = []
    pending = ""

    async def read_until_discovery() -> Mapping[str, Any]:
        nonlocal pending
        assert process.stderr is not None
        while True:
            chunk = await process.stderr.read(8192)
            if not chunk:
                final_text = decoder.decode(b"", final=True)
                if final_text:
                    pending += final_text
                if pending:
                    line = pending
                    pending = ""
                    stderr_lines.append(line)
                    parsed = parse_discovery_line(line)
                    if parsed is not None:
                        return parsed
                exit_code = process.returncode
                raise CursorSDKError(
                    f"Bridge exited before discovery with status {exit_code}: "
                    + "".join(stderr_lines)
                )
            pending += decoder.decode(chunk)
            while "\n" in pending:
                line, pending = pending.split("\n", 1)
                line += "\n"
                stderr_lines.append(line)
                parsed = parse_discovery_line(line)
                if parsed is not None:
                    return parsed

    try:
        return await asyncio.wait_for(read_until_discovery(), timeout=timeout)
    except asyncio.TimeoutError as exc:
        raise CursorSDKError("Timed out waiting for bridge discovery") from exc


async def _terminate_process(process: asyncio.subprocess.Process) -> None:
    if process.returncode is not None:
        return
    process.terminate()
    try:
        await asyncio.wait_for(process.wait(), timeout=5)
    except asyncio.TimeoutError:
        process.kill()
        try:
            await asyncio.wait_for(process.wait(), timeout=5)
        except asyncio.TimeoutError:
            pass
